// TRF_MapTargetWF - Map route to target workflow ID
const envelope = $('TRG_FromGate').item.json.envelope;
const agentOutput = $('Agent_Router').item.json || {};

// Parse router response - handle nested output object
let route = 'conversational';
let confidence = 0.5;
let hints = {};

try {
  // Check if output is nested in .output property (common with langchain agents)
  const routerData = agentOutput.output || agentOutput || {};

  if (routerData && typeof routerData === 'object' && routerData.route) {
    route = routerData.route.toLowerCase();
    confidence = routerData.confidence || 0.5;
    hints = routerData.hints || {};
  } else if (typeof routerData === 'string') {
    // Try to parse as JSON string - remove markdown code blocks
    const cleaned = routerData.replace(/\x60\x60\x60json\n?/g, '').replace(/\x60\x60\x60\n?/g, '').trim();
    const parsed = JSON.parse(cleaned);
    route = (parsed.route || 'conversational').toLowerCase();
    confidence = parsed.confidence || 0.5;
    hints = parsed.hints || {};
  }
} catch (e) {
  route = 'conversational';
  confidence = 0.3;
}

// Normalize route (UPDATED: added calendar and tasks)
const validRoutes = ['calendar', 'tasks', 'conversational', 'query', 'config', 'capture'];
if (validRoutes.indexOf(route) === -1) {
  route = 'conversational';
}

// Map route to workflow ID (UPDATED: added WF07 and WF08)
const routeMap = {
  calendar: 'wGuyX1RKJyU4BTqE',
  tasks: 'WQzoN1MwzHmv9TQr',
  conversational: '3ZzMCwFZcYM6pE1u',
  query: 'ULmkALrmYbBk7QqH',
  config: 'nz61poQpkCGoYX54',
  capture: 'zNOCKOmBHL5aocsG'
};

const target_wf_id = routeMap[route];
const start_time = Date.now();

return [{
  json: {
    envelope: envelope,
    router: {
      route: route,
      confidence: confidence,
      hints: hints
    },
    target_wf_id: target_wf_id,
    _meta: {
      start_time: start_time,
      trace_id: envelope.trace_id
    }
  }
}];

// TRF_FinalLog - Standardized logging
const mapOutput = $('TRF_MapTargetWF').item.json;
const dispatcherOutput = $('EXEC_Dispatcher').item.json || {};

const elapsed_ms = Date.now() - mapOutput._meta.start_time;

return [{
  json: {
    log: {
      trace_id: mapOutput._meta.trace_id,
      route: mapOutput.router.route,
      target_wf_id: mapOutput.target_wf_id,
      elapsed_ms: elapsed_ms,
      created_count: dispatcherOutput.created_count || 0,
      validation_flags: dispatcherOutput.validation_flags || {}
    },
    result: dispatcherOutput
  }
}];

// TRF_FallbackResponse: CATCH-ALL — garante que SEMPRE há envelope + resposta
// Reconhece TODOS os formatos de resposta dos sub-agents:
// - WF03/WF05 Conversational/Config: agent_response.text (string)
// - WF04 Query: agent_response.items (array) + query_meta (structured → vai para WF04B)
// - WF06 Capture: summary (string)

const input = $json || {};

// === ENVELOPE: pegar de múltiplas fontes ===
let envelope = {};
try { envelope = $('TRF_MapTargetWF').item.json.envelope || {}; } catch(e) {}
if (!envelope.from_phone) {
  try { envelope = $('TRG_FromGate').item.json.envelope || {}; } catch(e) {}
}
if (!envelope.from_phone) {
  envelope = input.envelope || {};
}

const userMessage = envelope.user_message || '';
let route = '';
try { route = $('TRF_MapTargetWF').item.json.router?.route || ''; } catch(e) {}

// === CHECK 1: Resposta com texto direto (WF03, WF05) ===
if (input.agent_response?.text && input.agent_response.text.length > 5) {
  return [{
    json: {
      ...input,
      envelope: envelope,
      response_text: input.agent_response.text,
      draft_text: input.agent_response.text,
      user_message: userMessage,
      _fallback: false
    }
  }];
}

// === CHECK 2: Resposta com summary (WF06 Capture) ===
if (input.summary && input.summary.length > 5) {
  return [{
    json: {
      envelope: envelope,
      agent_response: {
        text: input.summary,
        agent: 'CAPTURE',
        items_count: input.items_count || 0
      },
      response_text: input.summary,
      draft_text: input.summary,
      user_message: userMessage,
      _fallback: false
    }
  }];
}

// === CHECK 3: Resposta estruturada com items (WF04 Query) ===
// WF04 retorna agent_response.items (array) + query_meta
// Isso é VÁLIDO — os items serão formatados pelo WF04B
if (input.agent_response?.items && Array.isArray(input.agent_response.items)) {
  return [{
    json: {
      ...input,
      envelope: envelope,
      user_message: userMessage,
      _fallback: false
    }
  }];
}

// === CHECK 4: Resposta com query_meta (WF04 Query vazio) ===
// Mesmo sem items, se tem query_meta, é resposta válida do WF04
if (input.query_meta) {
  return [{
    json: {
      ...input,
      envelope: envelope,
      user_message: userMessage,
      _fallback: false
    }
  }];
}

// === CHECK 5: response_text ou output direto ===
if (input.response_text && input.response_text.length > 5) {
  return [{
    json: {
      ...input,
      envelope: envelope,
      agent_response: { text: input.response_text, agent: route || 'UNKNOWN' },
      draft_text: input.response_text,
      user_message: userMessage,
      _fallback: false
    }
  }];
}

// === NENHUMA RESPOSTA VÁLIDA — gerar fallback inteligente ===
let fallbackText = '';
if (route === 'query') {
  fallbackText = 'Tudo tranquilo por aqui! 😊 Não encontrei nenhum compromisso registrado. Quer que eu crie algum lembrete?';
} else if (route === 'capture') {
  fallbackText = 'Hmm, não consegui processar isso agora. Pode repetir o que gostaria de salvar? 🤔';
} else if (route === 'config') {
  fallbackText = 'Não consegui atualizar a configuração. Pode tentar novamente? ⚙️';
} else {
  fallbackText = 'Oi! Estou aqui para ajudar. O que precisa? 😊';
}

return [{
  json: {
    envelope: envelope,
    agent_response: {
      text: fallbackText,
      agent: 'FALLBACK',
      items_count: 0
    },
    response_text: fallbackText,
    draft_text: fallbackText,
    user_message: userMessage,
    _fallback: true,
    validation_flags: {}
  }
}];
